# VULNERABILITY: Insecure Direct Object Reference (IDOR) + Mass Assignment
# Any authenticated user can update ANY other user's profile including
# privileged fields like role, is_admin, credits, and subscription_tier.
# There are no authorization checks to verify:
# 1. That the user is updating their OWN profile (or is an admin)
# 2. That non-admin users cannot modify privileged fields (role, is_admin, credits, subscription_tier)

class UpdateUserProfile(Mutation):
    class Arguments:
        user_id = String(required=True, description="ID of the user to update")
        input = UpdateUserProfileInput(required=True)

    user = Field(UserType)
    success = Boolean()
    message = String()

    def mutate(self, info, user_id, input):
        # Check if requester is authenticated
        current_user = info.context.get("current_user")
        if not current_user:
            return UpdateUserProfile(user=None, success=False, message="Authentication required")

        # Look up the target user
        target_user = USERS_DB.get(user_id)
        if not target_user:
            return UpdateUserProfile(user=None, success=False, message="User not found")

        # VULNERABILITY: No check that current_user["id"] == user_id
        # Any authenticated user can modify any other user's profile.
        # Also no check restricting privileged fields (role, is_admin, credits,
        # subscription_tier) to admin-only access.

        # Apply all provided fields directly
        update_data = {k: v for k, v in input.items() if v is not None}

        # Convert enum values to their string representation
        if "role" in update_data:
            update_data["role"] = update_data["role"].value if hasattr(update_data["role"], 'value') else update_data["role"]
        if "subscription_tier" in update_data:
            update_data["subscription_tier"] = update_data["subscription_tier"].value if hasattr(update_data["subscription_tier"], 'value') else update_data["subscription_tier"]

        # Validate email format (basic)
        if "email" in update_data:
            email = update_data["email"]
            if "@" not in email or "." not in email:
                return UpdateUserProfile(user=None, success=False, message="Invalid email format")

        # Validate username length
        if "username" in update_data:
            username = update_data["username"]
            if len(username) < 3 or len(username) > 50:
                return UpdateUserProfile(user=None, success=False, message="Username must be between 3 and 50 characters")

        # Validate credits
        if "credits" in update_data:
            if update_data["credits"] < 0:
                return UpdateUserProfile(user=None, success=False, message="Credits cannot be negative")

        # Apply updates to the user record
        target_user.update(update_data)

        user_obj = UserType(
            id=target_user["id"],
            username=target_user["username"],
            email=target_user["email"],
            bio=target_user.get("bio", ""),
            role=target_user["role"],
            is_admin=target_user["is_admin"],
            credits=target_user["credits"],
            subscription_tier=target_user["subscription_tier"],
        )

        return UpdateUserProfile(user=user_obj, success=True, message="Profile updated successfully")


class Query(ObjectType):
    user = Field(UserType, user_id=String(required=True))
    me = Field(UserType)
    all_users = graphene.List(UserType)

    def resolve_user(self, info, user_id):
        current_user = info.context.get("current_user")
        if not current_user:
            return None
        user_data = USERS_DB.get(user_id)
        if not user_data:
            return None
        return UserType(**user_data)

    def resolve_me(self, info):
        current_user = info.context.get("current_user")
        if not current_user:
            return None
        user_data = USERS_DB.get(current_user["id"])
        if not user_data:
            return None
        return UserType(**user_data)

    def resolve_all_users(self, info):
        current_user = info.context.get("current_user")
        if not current_user:
            return []
        return [UserType(**data) for data in USERS_DB.values()]


class Mutations(ObjectType):
    update_user_profile = UpdateUserProfile.Field()


schema = Schema(query=Query, mutation=Mutations)


def execute_query(query_string, context=None, variables=None):
    """Helper to execute a GraphQL query with context."""
    if context is None:
        context = {}
    result = schema.execute(
        query_string,
        context_value=context,
        variable_values=variables,
    )
    if result.errors:
        print(f"Errors: {result.errors}")
    if result.data:
        print(f"Data: {result.data}")
    return result


